from dataclasses import dataclass
from typing import ClassVar, final, override

from pytoniq_core import Address, Cell, begin_cell
from pytoniq_core.tlb.account import TickTock

from .contract import Blueprint, ContractView, Provider


@dataclass
class ElectorState:
    def serialize(self) -> Cell:
        # data: dict dict dict grams uint32 uint256 — all zeros
        return begin_cell().store_uint(0, 1 + 1 + 1 + 4 + 32).store_uint(0, 256).end_cell()


class ElectorView(ContractView[ElectorState]):
    @override
    def _parse_state(self, state: Cell) -> ElectorState:
        return ElectorState()


# Compiled from auto/elector-code.fif — regenerate with extract_contract_bocs.py
ELECTOR_CODE = Cell.one_from_boc(
    ""
)


@final
class ElectorBlueprint(Blueprint[ElectorState]):
    CODE_BOC: ClassVar[Cell] = ELECTOR_CODE

    def __init__(self, workchain: int = -1):
        super().__init__(workchain, ElectorState())
        self.state_init.special = TickTock(tick=True, tock=False)
        self.address = Address((-1, b"\x33" * 32))

    @override
    def materialize(self, provider: Provider):
        return ElectorView(provider, self.address)
